import {ChangeEvent, Component} from "react";
import * as React from "react";
import {Button} from "antd";
import styled from "styled-components";

interface State {
    username: string,
    password: string
}

interface SignInProps {
    parentHandleSignIn:(username: string, password: string) => any;
}

const Row = styled.div`
    padding: 10px;
    display: flex;
    flex-direction: row;
`;


export class SignIn extends Component<SignInProps, State> {

    constructor(props: any) {
        super(props);
        this.state = {
            username: "",
            password: ""
        };

        this.handleUsernameChange = this.handleUsernameChange.bind(this);
        this.handlePasswordChange = this.handlePasswordChange.bind(this);
        this.handleLogin = this.handleLogin.bind(this);
    }

    handleUsernameChange(e: ChangeEvent<any>): void {
        this.setState( {username: e.target.value});
    }

    handlePasswordChange(e: ChangeEvent<any>): void {
        this.setState( {password: e.target.value});
    }

    handleLogin(e: ChangeEvent<any>): void {
        console.log("handleLogin Clicked");
        this.props.parentHandleSignIn(this.state.username, this.state.password).then((data: any) => {
                console.log('logged in');
                console.log(data);
            }
        );
    }

    render(): React.ReactNode {
        return (
            <div>
                <Row>
                    Username:
                    <input type="text" value={this.state.username} onChange={this.handleUsernameChange}/>
                </Row>
                <Row>
                    Password:
                    <input type="password" value={this.state.password} onChange={this.handlePasswordChange}/>
                </Row>
                <Button key="login" type="primary" htmlType="submit" onClick={this.handleLogin} style={{float: "right"}}>
                    Login
                </Button>
            </div>
        )
    }
}