import React from 'react';
import './App.css';
import axios from 'axios';
import {Component} from 'react';
import Cookie from 'js-cookie';
import * as Constants from '../utils/Constants';
import * as Session from '../utils/Session';
import {UploadApp} from "./UploadApp";
import {SignIn} from "./SignIn";

interface State {
    dev1SessionId: any
}

export class App extends Component<any, State> {
    constructor(props: any) {
        super(props);
        this.state = {
            dev1SessionId: Cookie.get(Constants.dev1CookieName)
        }
    }

    logout = () => {
        Session.logout();
        this.setState({ dev1SessionId: undefined });
    };

    parentHandleSignIn = async (username: string, password: string) => {
        console.log("inside parentHandleSignIn", username, password);
        const response = await axios({
            method: 'post',
            url: `/login`,
            headers: { 'Content-Type': 'application/json' },
            data: {
                username,
                password,
            },
        });
        console.log(response);
        this.setState({ dev1SessionId: response.data.dev1SessionId });

        return response.data.dev1SessionId;
    };


    render(): React.ReactNode {
        return (
            <div className="App">
                <header className="App-header">
                    <h1>Bulk App Uploader</h1>
                </header>
                {!this.state.dev1SessionId && <SignIn parentHandleSignIn={this.parentHandleSignIn}/>}

                {this.state.dev1SessionId && <UploadApp/>}
            </div>
        );
    }
}

export default App;
